class AnimatedListPage extends StatefulWidget {
  const AnimatedListPage({super.key});
  @override
  State<AnimatedListPage> createState() => _State();
}

class _State extends State<AnimatedListPage> {
  final _key = GlobalKey<AnimatedListState>();
  final List<String> _items = [];
  int _c = 0;

  void _add() {
    _items.add('Element ' + _c.toString());
    _key.currentState?.insertItem(_items.length - 1);
  }

  void _remove(int i) {
    final item = _items.removeAt(i);
    _key.currentState?.removeItem(i, (_, a) => SizeTransition(sizeFactor: a,
      child: Card(child: ListTile(leading: const Icon(Icons.delete, color: Colors.red), title: Text(item)))));
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(title: const Text('Animatsiyali Ro\'yxat')),
      floatingActionButton: FloatingActionButton(onPressed: _add, child: const Icon(Icons.add)),
      body: AnimatedList(
        key: _key, initialItemCount: _items.length, padding: const EdgeInsets.all(8),
        itemBuilder: (_, i, a) => SizeTransition(sizeFactor: a,
          child: Card(margin: const EdgeInsets.symmetric(horizontal: 16, vertical: 4),
            child: ListTile(
              leading: CircleAvatar(child: Text((i + 1).toString())),
              title: Text(_items[i]),
              trailing: IconButton(icon: const Icon(Icons.delete_outline, color: Colors.red), onPressed: () => _remove(i)),
            ))),
      ),
    );
  }
}

