import 'package:provider/provider.dart';

void main() => runApp(MultiProvider(
  providers: [
    ChangeNotifierProvider(create: (_) => CounterProvider()),
    ChangeNotifierProvider(create: (_) => ThemeProvider()),
  ], child: const MyApp()));

class MyApp extends StatelessWidget {
  const MyApp({super.key});
  @override
  Widget build(BuildContext context) {
    return Consumer<ThemeProvider>(builder: (_, tp, __) => MaterialApp(
      title: 'APP_NAME', debugShowCheckedModeBanner: false,
      themeMode: tp.dark ? ThemeMode.dark : ThemeMode.light,
      theme: ThemeData(colorSchemeSeed: Colors.blue, useMaterial3: true, brightness: Brightness.light),
      darkTheme: ThemeData(colorSchemeSeed: Colors.blue, useMaterial3: true, brightness: Brightness.dark),
      home: const HomePage()));
  }
}

class CounterProvider extends ChangeNotifier {
  int _c = 0; int get count => _c;
  void inc() { _c++; notifyListeners(); }
  void dec() { if (_c > 0) { _c--; notifyListeners(); } }
  void reset() { _c = 0; notifyListeners(); }
}

class ThemeProvider extends ChangeNotifier {
  bool _d = false; bool get dark => _d;
  void toggle() { _d = !_d; notifyListeners(); }
}

class HomePage extends StatelessWidget {
  const HomePage({super.key});
  @override
  Widget build(BuildContext context) {
    return Scaffold(appBar: AppBar(title: const Text('Provider Demo'),
      actions: [IconButton(icon: Icon(context.watch<ThemeProvider>().dark ? Icons.light_mode : Icons.dark_mode),
        onPressed: () => context.read<ThemeProvider>().toggle())]),
      body: Center(child: Column(mainAxisAlignment: MainAxisAlignment.center, children: [
        const Text('Hisoblagich:', style: TextStyle(fontSize: 20)),
        const SizedBox(height: 16),
        Text(context.watch<CounterProvider>().count.toString(), style: const TextStyle(fontSize: 48, fontWeight: FontWeight.bold)),
        const SizedBox(height: 24),
        Row(mainAxisAlignment: MainAxisAlignment.center, children: [
          FilledButton.tonal(onPressed: () => context.read<CounterProvider>().dec(), child: const Icon(Icons.remove)),
          const SizedBox(width: 16),
          FilledButton(onPressed: () => context.read<CounterProvider>().inc(), child: const Icon(Icons.add)),
          const SizedBox(width: 16),
          OutlinedButton(onPressed: () => context.read<CounterProvider>().reset(), child: const Text('Reset')),
        ]),
      ])),);
  }
}

