class _VideoPageState extends State<VideoPage> {
  late VideoPlayerController _ctrl;
  bool _init = false;
  @override
  void initState() {
    super.initState();
    _ctrl = VideoPlayerController.networkUrl(Uri.parse('https://example.com/video.mp4'))
      ..initialize().then((_) => setState(() => _init = true));
  }
  @override
  void dispose() { _ctrl.dispose(); super.dispose(); }
  @override
  Widget build(BuildContext context) {
    return Scaffold(appBar: AppBar(title: const Text('Video')),
      body: Center(child: _init ? AspectRatio(aspectRatio: _ctrl.value.aspectRatio, child: VideoPlayer(_ctrl)) : const CircularProgressIndicator()),
      floatingActionButton: FloatingActionButton(onPressed: () => setState(() => _ctrl.value.isPlaying ? _ctrl.pause() : _ctrl.play()),
        child: Icon(_ctrl.value.isPlaying ? Icons.pause : Icons.play_arrow)));
  }
}

