import 'package:flutter/material.dart';

class ResponsiveLayout extends StatelessWidget {
  final Widget mobile, tablet, desktop;
  const ResponsiveLayout({super.key, required this.mobile, required this.tablet, required this.desktop});
  static bool isMobile(BuildContext c) => MediaQuery.of(c).size.width < 600;
  static bool isTablet(BuildContext c) => MediaQuery.of(c).size.width >= 600 && MediaQuery.of(c).size.width < 1200;
  static bool isDesktop(BuildContext c) => MediaQuery.of(c).size.width >= 1200;
  @override
  Widget build(BuildContext context) {
    return LayoutBuilder(builder: (context, constraints) {
      if (constraints.maxWidth >= 1200) return desktop;
      if (constraints.maxWidth >= 600) return tablet;
      return mobile;
    });
  }
}

import 'package:flutter/material.dart';

final counter = ValueNotifier<int>(0);

void main() => runApp(const MyApp());

class MyApp extends StatelessWidget {
  const MyApp({super.key});
  @override
  Widget build(BuildContext context) {
    return MaterialApp(title: 'APP_NAME', debugShowCheckedModeBanner: false,
      theme: ThemeData(colorSchemeSeed: Colors.blue, useMaterial3: true),
      home: Scaffold(appBar: AppBar(title: const Text('ValueNotifier')),
        body: Center(child: ValueListenableBuilder<int>(valueListenable: counter,
          builder: (_, count, __) => Text(count.toString(), style: const TextStyle(fontSize: 48, fontWeight: FontWeight.bold)))),
        floatingActionButton: Row(mainAxisAlignment: MainAxisAlignment.end, children: [
          FloatingActionButton(heroTag: 'dec', onPressed: () => counter.value--, child: const Icon(Icons.remove)),
          const SizedBox(width: 16),
          FloatingActionButton(heroTag: 'inc', onPressed: () => counter.value++, child: const Icon(Icons.add)),
        ])));
  }
}
